import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';

const OwnerLogin = () => {
    const navigate = useNavigate();
    const [formData, setFormData] = useState({
        email: '',
        password: ''
    });
    const [error, setError] = useState('');

    const handleSubmit = (e) => {
        e.preventDefault();
        if (formData.email && formData.password) {
            localStorage.setItem('ownerToken', 'demo-owner-token');
            localStorage.setItem('ownerEmail', formData.email);
            navigate('/owner-dashboard');
        } else {
            setError('Please fill all fields');
        }
    };

    return ( <
        div className = "min-h-screen bg-gradient-to-b from-gray-900 to-gray-800 flex items-center justify-center py-12 px-4" >
        <
        div className = "bg-gray-800 rounded-xl p-8 max-w-md w-full" >
        <
        div className = "text-center mb-8" >
        <
        div className = "flex justify-center mb-4" >
        <
        span className = "text-red-600 text-5xl" > 🏢 < /span> <
        /div> <
        h2 className = "text-3xl font-bold text-white" > Theatre Owner Login < /h2> <
        p className = "text-gray-400 mt-2" > Login to manage your theatre < /p> <
        /div>

        {
            error && ( <
                div className = "bg-red-600 text-white p-3 rounded-lg mb-4" > { error } <
                /div>
            )
        }

        <
        form onSubmit = { handleSubmit } >
        <
        div className = "mb-4" >
        <
        label className = "block text-gray-300 mb-2" > Email Address < /label> <
        input type = "email"
        value = { formData.email }
        onChange = {
            (e) => setFormData({...formData, email: e.target.value }) }
        className = "w-full px-4 py-2 bg-gray-700 text-white rounded-lg focus:outline-none focus:ring-2 focus:ring-red-500"
        placeholder = "Enter registered email"
        required /
        >
        <
        /div>

        <
        div className = "mb-6" >
        <
        label className = "block text-gray-300 mb-2" > Password < /label> <
        input type = "password"
        value = { formData.password }
        onChange = {
            (e) => setFormData({...formData, password: e.target.value }) }
        className = "w-full px-4 py-2 bg-gray-700 text-white rounded-lg focus:outline-none focus:ring-2 focus:ring-red-500"
        placeholder = "Enter your password"
        required /
        >
        <
        /div>

        <
        button type = "submit"
        className = "w-full bg-red-600 text-white py-3 rounded-lg hover:bg-red-700 transition font-semibold" >
        Login as Owner <
        /button> <
        /form>

        <
        div className = "mt-6 text-center" >
        <
        p className = "text-gray-400" >
        New to CineBook ? { ' ' } <
        button onClick = {
            () => navigate('/owner-signup') }
        className = "text-red-500 hover:text-red-400" >
        Register Your Theatre <
        /button> <
        /p> <
        button onClick = {
            () => navigate('/') }
        className = "text-gray-400 hover:text-white mt-4 block" > ←Back to Home <
        /button> <
        /div>

        <
        div className = "mt-8 p-4 bg-gray-700 rounded-lg" >
        <
        p className = "text-white text-sm font-semibold mb-2" > Demo Credentials : < /p> <
        p className = "text-gray-300 text-xs" > Email: owner @example.com < /p> <
        p className = "text-gray-300 text-xs" > Password: any password < /p> <
        /div> <
        /div> <
        /div>
    );
};

export default OwnerLogin;
